        downloadButton: 'Descargar',
        autoDeletedPrefix: 'Borrado automático del servidor en',
        autoDeletedHint: 'La descarga comienza automáticamente. Si tu navegador la bloqueó, pulsa el botón de arriba antes de que se acabe el tiempo.',
