//Apply the current locale to every element carrying a data-i18n
//attribute. Values may include inline HTML (links, em); innerHTML
//is safe here because the values come from the static module above,
//not from user input.
export function applyTranslations(lang)
{
    const dict = TRANSLATIONS[lang] || TRANSLATIONS.en;
    document.documentElement.lang = lang;
    document.querySelectorAll('[data-i18n]').forEach((node) =>
    {
        const key = node.getAttribute('data-i18n');
        const value = dict[key];
        if (typeof value === 'string')
        {
            node.innerHTML = value;
        }
    });
}


export function detectInitialLang()
{
    const saved = localStorage.getItem('helios-lidar-lang');
    if (saved && SUPPORTED_LANGS.includes(saved)) return saved;
    const browser = (navigator.language || 'en').toLowerCase().slice(0, 2);
    return SUPPORTED_LANGS.includes(browser) ? browser : 'en';
}


export function persistLang(lang)
{
    try { localStorage.setItem('helios-lidar-lang', lang); }
    catch (_e) { /* private mode etc, fail silently */ }
}
